// 섹션 1️⃣: 분산 트레이싱 (Distributed Tracing)
// ============================================================================

// TraceID: 고유한 요청 추적 ID
type TraceID string

// GenerateTraceID: Trace ID 생성
func GenerateTraceID() TraceID {
	return TraceID(fmt.Sprintf("trace-%d-%d", time.Now().Unix(), rand.Int63()))
}

// Span: 각 서비스의 처리 시간 기록
type Span struct {
	TraceID   TraceID       `json:"trace_id"`
	SpanID    string        `json:"span_id"`
	Service   string        `json:"service"`
	Operation string        `json:"operation"`
	StartTime time.Time     `json:"start_time"`
	EndTime   time.Time     `json:"end_time"`
	Duration  time.Duration `json:"duration_ms"`
	Status    string        `json:"status"` // "success", "error"
}

// SpanRecorder: Span 기록 저장소
type SpanRecorder struct {
	spans []*Span
	mu    sync.Mutex
}

// NewSpanRecorder 생성
func NewSpanRecorder() *SpanRecorder {
	return &SpanRecorder{
		spans: make([]*Span, 0),
	}
}

// RecordSpan: Span 기록
func (sr *SpanRecorder) RecordSpan(span *Span) {
	sr.mu.Lock()
	defer sr.mu.Unlock()

	span.Duration = span.EndTime.Sub(span.StartTime)
	sr.spans = append(sr.spans, span)

	fmt.Printf("[Span] %s → %s: %v (%dms)\n",
		span.Service, span.Operation, span.Status, span.Duration.Milliseconds())
}

// GetTrace: Trace ID로 모든 Span 조회
func (sr *SpanRecorder) GetTrace(traceID TraceID) []*Span {
	sr.mu.Lock()
	defer sr.mu.Unlock()

	var result []*Span
	for _, span := range sr.spans {
		if span.TraceID == traceID {
			result = append(result, span)
		}
	}
	return result
}

// ============================================================================
// 섹션 2️⃣: Context와 Trace ID 결합
// ============================================================================

// ContextKey: Context에서 사용할 키
type ContextKey string

const (
	TraceIDKey ContextKey = "trace_id"
	SpanIDKey  ContextKey = "span_id"
)

// ContextWithTraceID: Context에 Trace ID 저장
func ContextWithTraceID(ctx context.Context, traceID TraceID) context.Context {
	return context.WithValue(ctx, TraceIDKey, traceID)
}

// GetTraceID: Context에서 Trace ID 추출
func GetTraceID(ctx context.Context) TraceID {
	traceID, ok := ctx.Value(TraceIDKey).(TraceID)
	if !ok {
		return "unknown"
	}
	return traceID
}

// ContextWithSpanID: Context에 Span ID 저장
func ContextWithSpanID(ctx context.Context, spanID string) context.Context {
	return context.WithValue(ctx, SpanIDKey, spanID)
}

