// 섹션 3️⃣: Prometheus 메트릭 (Counter, Gauge, Histogram)
// ============================================================================

// SimpleMetrics: 간단한 메트릭 수집 (Prometheus 대체)
type SimpleMetrics struct {
	requestCount      int64
	errorCount        int64
	requestDurations  []time.Duration
	activeConnections int64
	mu                sync.Mutex
}

// NewSimpleMetrics 생성
func NewSimpleMetrics() *SimpleMetrics {
	return &SimpleMetrics{
		requestDurations: make([]time.Duration, 0),
	}
}

// Counter: 요청 수 증가
func (sm *SimpleMetrics) IncCounter() {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	sm.requestCount++
}

// Counter: 에러 수 증가
func (sm *SimpleMetrics) IncErrors() {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	sm.errorCount++
}

// Gauge: 활성 연결 증가
func (sm *SimpleMetrics) IncConnections() {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	sm.activeConnections++
}

// Gauge: 활성 연결 감소
func (sm *SimpleMetrics) DecConnections() {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	if sm.activeConnections > 0 {
		sm.activeConnections--
	}
}

// Histogram: 요청 시간 기록
func (sm *SimpleMetrics) RecordDuration(d time.Duration) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	sm.requestDurations = append(sm.requestDurations, d)
}

// GetMetrics: 메트릭 조회
func (sm *SimpleMetrics) GetMetrics() map[string]interface{} {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	var avgDuration time.Duration
	if len(sm.requestDurations) > 0 {
		totalDuration := time.Duration(0)
		for _, d := range sm.requestDurations {
			totalDuration += d
		}
		avgDuration = totalDuration / time.Duration(len(sm.requestDurations))
	}

	errorRate := 0.0
	if sm.requestCount > 0 {
		errorRate = float64(sm.errorCount) / float64(sm.requestCount) * 100
	}

	return map[string]interface{}{
		"request_count":       sm.requestCount,
		"error_count":         sm.errorCount,
		"error_rate_percent":  errorRate,
		"avg_duration_ms":     avgDuration.Milliseconds(),
		"active_connections":  sm.activeConnections,
		"total_request_sizes": len(sm.requestDurations),
	}
}

// ============================================================================
// 섹션 4️⃣: 구조화된 로깅 (slog)
