// StructuredLogger: slog 래퍼
type StructuredLogger struct {
	logger *slog.Logger
}

// NewStructuredLogger 생성
func NewStructuredLogger() *StructuredLogger {
	handler := slog.NewJSONHandler(os.Stdout, nil)
	logger := slog.New(handler)

	return &StructuredLogger{
		logger: logger,
	}
}

// Info: 정보 레벨 로그
func (sl *StructuredLogger) Info(ctx context.Context, msg string, args ...interface{}) {
	traceID := GetTraceID(ctx)
	allArgs := []interface{}{"trace_id", traceID}
	allArgs = append(allArgs, args...)

	sl.logger.InfoCtx(ctx, msg, allArgs...)
	fmt.Printf("[INFO] %s: %s\n", traceID, msg)
}

// Error: 에러 레벨 로그
func (sl *StructuredLogger) Error(ctx context.Context, msg string, err error, args ...interface{}) {
	traceID := GetTraceID(ctx)
	allArgs := []interface{}{"trace_id", traceID, "error", err.Error()}
	allArgs = append(allArgs, args...)

	sl.logger.ErrorCtx(ctx, msg, allArgs...)
	fmt.Printf("[ERROR] %s: %s (error: %v)\n", traceID, msg, err)
}

