// 섹션 5️⃣: Golden Signals 수집
// ============================================================================

// GoldenSignals: 시스템 건강도 4가지 신호
type GoldenSignals struct {
	Latency   time.Duration // 평균 레이턴시
	Errors    float64       // 에러율 (%)
	Traffic   int64         // 초당 요청 수
	Saturation float64      // 포화도 (%)
}

// RequestMetrics: 요청별 메트릭
type RequestMetrics struct {
	StartTime time.Time
	EndTime   time.Time
	Success   bool
	DataSize  int
}

// GoldenSignalCollector: Golden Signals 수집기
type GoldenSignalCollector struct {
	metrics []*RequestMetrics
	mu      sync.Mutex
}

// NewGoldenSignalCollector 생성
func NewGoldenSignalCollector() *GoldenSignalCollector {
	return &GoldenSignalCollector{
		metrics: make([]*RequestMetrics, 0),
	}
}

// RecordRequest: 요청 메트릭 기록
func (gsc *GoldenSignalCollector) RecordRequest(rm *RequestMetrics) {
	gsc.mu.Lock()
	defer gsc.mu.Unlock()
	gsc.metrics = append(gsc.metrics, rm)
}

// CalculateSignals: Golden Signals 계산
func (gsc *GoldenSignalCollector) CalculateSignals() GoldenSignals {
	gsc.mu.Lock()
	defer gsc.mu.Unlock()

	if len(gsc.metrics) == 0 {
		return GoldenSignals{}
	}

	// Latency (평균)
	totalLatency := time.Duration(0)
	for _, m := range gsc.metrics {
		totalLatency += m.EndTime.Sub(m.StartTime)
	}
	avgLatency := totalLatency / time.Duration(len(gsc.metrics))

	// Errors (에러율)
	errorCount := 0
	for _, m := range gsc.metrics {
		if !m.Success {
			errorCount++
		}
	}
	errorRate := float64(errorCount) / float64(len(gsc.metrics)) * 100

	// Traffic (초당 요청 수)
	now := time.Now()
	recentCount := int64(0)
	for _, m := range gsc.metrics {
		if now.Sub(m.StartTime) < 1*time.Second {
			recentCount++
		}
	}

	// Saturation (간단한 시뮬레이션: 요청 수로 계산)
	saturation := float64(len(gsc.metrics)) / 100.0 * 100.0 // 최대 100개 기준
	if saturation > 100 {
		saturation = 100
	}

	return GoldenSignals{
		Latency:    avgLatency,
		Errors:     errorRate,
		Traffic:    recentCount,
		Saturation: saturation,
	}
}

// ============================================================================
// 섹션 6️⃣: Observable Service 구현
// ============================================================================

// ObservableService: 관찰 가능한 서비스
type ObservableService struct {
	name           string
	logger         *StructuredLogger
	metrics        *SimpleMetrics
	spanRecorder   *SpanRecorder
	signalCollector *GoldenSignalCollector
}

// NewObservableService 생성
func NewObservableService(name string) *ObservableService {
	return &ObservableService{
		name:            name,
		logger:          NewStructuredLogger(),
		metrics:         NewSimpleMetrics(),
		spanRecorder:    NewSpanRecorder(),
		signalCollector: NewGoldenSignalCollector(),
	}
}

// ProcessRequest: 요청 처리 (관찰 가능성 포함)
func (os *ObservableService) ProcessRequest(ctx context.Context, requestID string) (bool, error) {
	start := time.Now()
	os.metrics.IncCounter()
	os.metrics.IncConnections()
	defer os.metrics.DecConnections()

	traceID := GetTraceID(ctx)

	// 요청 처리 시작 로깅
	os.logger.Info(ctx, fmt.Sprintf("%s 요청 처리 시작", os.name),
		"request_id", requestID,
		"service", os.name,
	)

	// Span 기록 시작
	spanID := fmt.Sprintf("span-%d", time.Now().Unix())
	ctx = ContextWithSpanID(ctx, spanID)

	// 비즈니스 로직 시뮬레이션
	time.Sleep(time.Duration(rand.Intn(100)) * time.Millisecond)

	// 성공/실패 시뮬레이션
	success := rand.Float32() > 0.1 // 90% 성공
	if !success {
		os.metrics.IncErrors()
		os.logger.Error(ctx, fmt.Sprintf("%s 요청 처리 실패", os.name), nil,
			"request_id", requestID,
			"service", os.name,
		)
	}

	// Span 기록
	duration := time.Now().Sub(start)
	os.metrics.RecordDuration(duration)

	status := "success"
	if !success {
		status = "error"
	}

	span := &Span{
		TraceID:   traceID,
		SpanID:    spanID,
		Service:   os.name,
		Operation: "ProcessRequest",
		StartTime: start,
		EndTime:   time.Now(),
		Status:    status,
	}
	os.spanRecorder.RecordSpan(span)

	// 요청 메트릭 기록
	os.signalCollector.RecordRequest(&RequestMetrics{
		StartTime: start,
		EndTime:   time.Now(),
		Success:   success,
		DataSize:  rand.Intn(1000),
	})

	os.logger.Info(ctx, fmt.Sprintf("%s 요청 처리 완료", os.name),
		"request_id", requestID,
		"duration_ms", duration.Milliseconds(),
		"service", os.name,
	)

	return success, nil
}

// GetMetrics: 메트릭 조회
func (os *ObservableService) GetMetrics() map[string]interface{} {
	return os.metrics.GetMetrics()
}

// ============================================================================
// 섹션 7️⃣: 에러 추적 및 로깅
// ============================================================================

// ErrorTracker: 에러 추적
type ErrorTracker struct {
	errors map[string]int
	mu     sync.Mutex
}

// NewErrorTracker 생성
func NewErrorTracker() *ErrorTracker {
	return &ErrorTracker{
		errors: make(map[string]int),
	}
}

// TrackError: 에러 추적
func (et *ErrorTracker) TrackError(ctx context.Context, errorType string, logger *StructuredLogger) {
	et.mu.Lock()
	defer et.mu.Unlock()

	et.errors[errorType]++

	logger.Error(ctx, "에러 발생",
		fmt.Errorf(errorType),
		"error_type", errorType,
		"count", et.errors[errorType],
		"file", "service.go",
		"line", 42,
	)
}

// GetErrorStats: 에러 통계
func (et *ErrorTracker) GetErrorStats() map[string]int {
	et.mu.Lock()
	defer et.mu.Unlock()

	result := make(map[string]int)
	for k, v := range et.errors {
		result[k] = v
	}
	return result
}

